import java.io.*;
import java.util.HashMap;
import java.util.Map;

public class DiskCache {
    private final String cacheDirectory;

    public DiskCache(String directory) {
        this.cacheDirectory = directory;
        File dir = new File(cacheDirectory);
        if (!dir.exists()) {
            dir.mkdirs();
        }
    }

    public void put(String key, Serializable value) throws IOException {
        try (ObjectOutputStream oos = new ObjectOutputStream(new FileOutputStream(new File(cacheDirectory + "/" + key)))) {
            oos.writeObject(value);
        }
    }

    public <T> T get(String key, Class<T> clazz) throws IOException, ClassNotFoundException {
        File file = new File(cacheDirectory + "/" + key);
        if (!file.exists()) {
            return null;
        }
        try (ObjectInputStream ois = new ObjectInputStream(new FileInputStream(file))) {
            return clazz.cast(ois.readObject());
        }
    }

    public void remove(String key) {
        File file = new File(cacheDirectory + "/" + key);
        if (file.exists()) {
            file.delete();
        }
    }

    public boolean containsKey(String key) {
        return new File(cacheDirectory + "/" + key).exists();
    }

    public static void main(String[] args) {
        try {
            DiskCache cache = new DiskCache("cache");

            // Example of putting an object into the cache
            Map<String, String> userPreferences = new HashMap<>();
            userPreferences.put("theme", "dark");
            userPreferences.put("language", "en");
            cache.put("user123", userPreferences);

            // Example of retrieving an object from the cache
            Map<String, String> retrievedPreferences = cache.get("user123", Map.class);
            if (retrievedPreferences != null) {
                System.out.println("Retrieved preferences: " + retrievedPreferences);
            }

            // Example of removing an object from the cache
            cache.remove("user123");
        } catch (IOException | ClassNotFoundException e) {
            e.printStackTrace();
        }
    }
}